var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 26일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年9月26日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年9月26日 倫敦，白教堂\\n<color=#ffd34c>深夜</color>","SCN":"1888年9月26日 伦敦，白教堂\\n<color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_A","text":{"KOREA":"벌써 한 달 정도 지난 일이라 잘 기억은 안 나지만…….","JPN":"もう一か月も前だからおぼろげだけど……","ENG":"I don't remember clearly because it's been about a month...","TWN":"已經過一個月了，我記不太清了……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_A","text":{"KOREA":"아! 그래요. 죽은 시체 옆에 백묵으로 <color=#ffd34c>낙서</color>가 쓰여 있었어요.","JPN":"ああ、そうだ。死体の横に、チョークで書かれた<color=#ffd34c>落書き</color>がありました。","ENG":"Oh! Yes. There were <color=#ffd34c>writings</color> next to the corpse in chalk.","TWN":"啊！對了。屍體旁邊用白粉筆寫了某些<color=#ffd34c>塗鴉</color>。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_A","text":{"KOREA":"그게 무슨 낙서였더라…….","JPN":"なんて書いてあったっけ……","ENG":"Now, what was it...?","TWN":"那是什麼來著……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_B","text":{"KOREA":"시체는 날카로운 날붙이 같은 것으로 <color=#ffd34c>신체 일부</color>가 훼손되어 있었소.","JPN":"死体は刃物みたいなもので<color=#ffd34c>体の一部</color>が傷つけられていた。","ENG":"<color=#ffd34c>A part of the body</color> was cut from the corpse with what looked like a sharp blade.","TWN":"<color=#ffd34c>身體的一部分</color>被鋒利的刀具破壞了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_B","text":{"KOREA":"내가 봤던 두 번째 희생자의 경우…….","JPN":"俺が見た二人目の犠牲者は……","ENG":"As for the second victim I saw...","TWN":"我看到的第二個受害者的情況就是這樣……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_C","text":{"KOREA":"그날 밤에 덩치가 크고, 검은 갑옷을 입고 있는 사람을 봤어요.","JPN":"あの夜、体が大きくて黒い鎧を来ている人を見ました。","ENG":"That night, I saw a large person wearing black armor.","TWN":"那天晚上，我看到一個身材高大，穿著黑色盔甲的人。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WITHMESS_SWANSONG_NPC_C","text":{"KOREA":"한 눈을 판 사이에 어디론가 사라져 버렸지만……. 정말이에요. 제가 똑똑히 봤다고요!","JPN":"ちょっとよそ見してる間にどこかに消えてしまったけど……本当です。確かに見たんです！","ENG":"I looked away for a second and no one was there... I'm telling you the truth! I know what I saw!","TWN":"一眨眼的功夫就不見了……真的，我看得清清楚楚！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"WITHMESS_SWANSONG_NPC_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"벌써 동이 트기 시작했군. 아무래도 오늘 밤 조사는 여기서 마치도록 하지.","JPN":"もう夜が明ける時間だな。今夜の調査はここまでにしよう。","ENG":"The sun is about to rise. Let's end our investigation here for tonight.","TWN":"天已經快亮了。今晚的調查就到這裡好了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 이쯤에서 수집한 정보를 정리해 보도록 할까?","JPN":"では今まで集めた情報をまとめてみるか。","ENG":"Then, shall we try to summarize the information we've collected so far?","TWN":"那麼，讓我們整理一下收集到的資訊吧？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"되도록 일목요연하게 부탁하지, 스완.","JPN":"スワン、なるべく一目瞭然にまとめてくれ。","ENG":"Please make it as clear as possible, Swan.","TWN":"請儘量簡明扼要，史旺。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥, 빨리 끝내고 싶은 건 저도 마찬가지라고요.","JPN":"ふん、早く終わらせたいのは私も同じなんですよ。","ENG":"Hmph. I also want to end this quickly.","TWN":"哼，我也想快點結束。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흠흠……!","JPN":"ごほん……！","ENG":"Ahem...!","TWN":"咳嗯……！"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 저지른 두 사건에는 <color=#ffd34c>공통점</color>이 있었어요.","JPN":"深夜の殺人鬼が犯した二つの事件には<color=#ffd34c>共通点</color>があります。","ENG":"The two incidents committed by the Midnight Killer have a few <color=#ffd34c>commonalities</color>.","TWN":"午夜殺人魔犯下的兩起案件有幾個<color=#ffd34c>共同點</color>。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"날카로운 금속 날붙이로 범행을 저지른 점, 신체 중 일부가 유독 심하게 훼손되었다는 점.","JPN":"凶器は鋭い金属の刃物だという点、体の一部がひどく損傷していた点。","ENG":"One is that a sharp metal blade was used, and another is that the certain parts of the body were mutilated.","TWN":"兇手用鋒利的金屬刀具作案，並且受害人身體的某些部位被特別嚴重地破壞了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 현장에는 의미를 알 수 없는 낙서가 있었다는 점이죠.","JPN":"そして現場に意味不明な落書きが残されていた点ですね。","ENG":"Also, there was a writing of some sort left behind on the scene.","TWN":"另外，現場還有一些無法理解的塗鴉。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나쁘지 않군.","JPN":"悪くない。","ENG":"Not bad.","TWN":"不錯。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"개요는 그 정도면 충분해. 이번에는 피해자에 대해 한 번 정리해보겠나?","JPN":"概要はそれで十分だ。今度は被害者の情報をまとめてくれるか？","ENG":"That's enough of an overview. Could you summarize the victims this time?","TWN":"概括就到這裡吧。這次能整理一下受害者的情況嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"먼저, 첫 번째 희생자는 모자 가게에서 일하던 마리 앤 니콜스.","JPN":"一人目の犠牲者は、帽子屋で働いていたマリ・アン・ニコルス。","ENG":"The first victim was Marie Ann Nicholes who worked at a hat shop.","TWN":"首先，第一個受害者是帽子店工作的瑪麗安·尼科爾斯。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나이는 17세. 생일은 6월 30일. <color=#ffd34c>흉부</color>가 훼손되어 있었죠.","JPN":"6月30日生まれの17歳。<color=#ffd34c>胸部</color>が損傷していました。","ENG":"Seventeen years old. Born on June 30th. And had her <color=#ffd34c>chest</color> mutilated.","TWN":"年齡是17歲。生日是6月30日。被破壞部位為<color=#ffd34c>胸部</color>。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"증언에 따르면, 현장에 남아 있던 낙서는…….","JPN":"証言によると、現場に残されていた落書きは……","ENG":"According to witness statements, the writing left on the scene is...","TWN":"根據證詞，現場留下的塗鴉是……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그녀가 첫 번째 시련을 지나, 내게 오게 하노라. 그녀는 은과 같이 되리라.</color>","JPN":"<color=#ffd34c>彼女が一つ目の試練を越え、私へと向かわせる。彼女は銀のようになるだろう。</color>","ENG":"<color=#ffd34c>Let her come through the first ordeal to me. And she will be as silver.</color>","TWN":"<color=#ffd34c>讓她經歷第一之裁判吧。來到我面前，她將如銀一般純淨。</color>"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으음, 글쎄요. 이게 무슨 뜻인지는 잘 모르겠네요.","JPN":"うーん。この言葉の意味はよくわかりませんね。","ENG":"Hmm, well. I'm not sure what that's supposed to mean.","TWN":"嗯，不好說。這是什麼意思我也不太清楚。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 두 번째 희생자. 가정부였던 허니 채프먼.","JPN":"そして二人目の犠牲者。家政婦として働いていたハニー・チャップマン。","ENG":"And our second victim was a housewife named Honey Chapman.","TWN":"然後是第二個受害者，曾是女傭的哈妮·查普曼。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나이는 21세. 생일은 1월 23일. 오른쪽 <color=#ffd34c>무릎</color>이 훼손되었죠.","JPN":"1月23日生まれの21歳。右側の<color=#ffd34c>膝</color>が損傷していました。","ENG":"Twenty-one years old. Born on January 23rd. Her right <color=#ffd34c>knee</color> was severely damaged.","TWN":"年齡21歲。生日是1月23日。被破壞的部位是右側的<color=#ffd34c>膝蓋</color>。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};